// Percorre todos os itens de entrada
for (const item of $input.all()) {
  if (item.json.nodes) {
    for (const node of item.json.nodes) {
      // Lista de tipos de nós que precisam de retry
      const retryNodes = [
        'n8n-nodes-base.googleSheets',
        'n8n-nodes-base.httpRequest',
        'n8n-nodes-base.mySql',
        'n8n-nodes-base.clickUp',
        'n8n-nodes-base.ssh',
        'n8n-nodes-base.googleDrive',
        'n8n-nodes-base.facebookGraphApi',
        'n8n-nodes-base.discord',
        'n8n-nodes-base.github',
        'n8n-nodes-base.extractFromFile',
        'n8n-nodes-base.urlScanIo',
        'n8n-nodes-base.telegram',
        'n8n-nodes-base.spreadsheetFile',
        'n8n-nodes-base.gmail',
        'n8n-nodes-base.googleCalendar',
        'n8n-nodes-base.n8n',
        'n8n-nodes-base.postgres',
        'n8n-nodes-base.googleBigQuery',
        'n8n-nodes-evolution-api.httpBin',
        'n8n-nodes-base.executeWorkflow'
      ];

      // Aplica configurações de retry se o nó estiver na lista
      if (retryNodes.includes(node.type)) {
        node.retryOnFail = true;
        node.maxTries = 5;
        node.waitBetweenTries = 5000;
      }

      // Configuração específica para Google Sheets
      if (node.type === 'n8n-nodes-base.executeWorkflow') {
        node.retryOnFail = false;
      }

      // Configuração específica para Google Sheets
      if (node.type === 'n8n-nodes-base.googleSheets') {
        node.parameters.options = node.parameters.options || {};
        node.parameters.options.useAppend = true;
      }

      // Configuração específica para MySQL
      if (node.type === 'n8n-nodes-base.mySql') {
        node.parameters.options = node.parameters.options || {};
        node.parameters.options.queryBatching = "single";
        node.parameters.options.replaceEmptyStrings = true;
      }

      // Remove `options` se estiver vazio
      if (node.parameters.options && Object.keys(node.parameters.options).length === 0) {
        delete node.parameters.options;
      }
    }
  }
}

// Retorna os itens de entrada modificados
return $input.all();
